def find_nth_digit(numerator, denominator, n):
    """
    Find the nth digit in the proper fraction of two given numbers.

    Args:
        numerator (int): The numerator of the fraction.
        denominator (int): The denominator of the fraction.
        n (int): The position of the digit to find.

    Returns:
        int: The nth digit in the proper fraction.
    """
    # Calculate the decimal representation of the fraction
    decimal = numerator / denominator

    # Convert the decimal to a string and remove the leading '0.'
    decimal_str = str(decimal)[2:]

    # If the decimal representation is finite, find the nth digit
    if '.' not in decimal_str:
        if n <= len(decimal_str):
            return int(decimal_str[n-1])
        else:
            return 0
    else:
        # Find the repeating part of the decimal representation
        remainder = numerator % denominator
        remainders = {}
        decimal_part = ''
        while remainder not in remainders and remainder != 0:
            remainders[remainder] = len(decimal_part)
            remainder *= 10
            decimal_part += str(remainder // denominator)
            remainder %= denominator

        # If the decimal representation is non-repeating, find the nth digit
        if remainder == 0:
            if n <= len(decimal_part):
                return int(decimal_part[n-1])
            else:
                return 0
        else:
            # Find the start and length of the repeating part
            start = remainders[remainder]
            length = len(decimal_part) - start

            # Find the nth digit in the repeating part
            if n <= start:
                return int(decimal_part[n-1])
            else:
                return int(decimal_part[(n-start-1) % length + start])
