def is_prime(n):
    """Check if a number is prime."""
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def is_newman_shanks_williams_prime(n):
    """Check if a number is a Newman-Shanks-Williams prime."""
    if not is_prime(n):
        return False
    k = 1
    while True:
        if (k**3 + 1) % n == 0:
            return True
        k += 1
        if k > n:
            return False

def nth_newman_shanks_williams_prime(n):
    """Find the nth Newman-Shanks-Williams prime number."""
    count = 0
    num = 2
    while True:
        if is_newman_shanks_williams_prime(num):
            count += 1
            if count == n:
                return num
        num += 1

