def check_alternating_string(s):
    # If string length is less than 2, it cannot be alternating
    if len(s) < 2:
        return False

    # Initialize variables to store the two alternating characters
    char1 = s[0]
    char2 = None

    # Iterate over the string to find the two alternating characters
    for i in range(1, len(s)):
        if s[i] != char1:
            if char2 is None:
                char2 = s[i]
            elif s[i] != char2:
                return False

    # If we have found two alternating characters, check if they alternate
    if char2 is None:
        return False
    for i in range(len(s)):
        if i % 2 == 0 and s[i] != char1:
            return False
        if i % 2 != 0 and s[i] != char2:
            return False

    return True

